#include <iostream>
using namespace std;
int ans2[20],ans=0,a[20],b[50],c[50],n;
//行+列，行-列+20
void print()
{
    for(int i=1;i<=n;i++) cout<<ans2[i]<<' ';
    cout<<'\n';
}
void dfs(int x)
{
    if(x==n+1)
    {
        if(ans<3) print();
        ans++;
        return ;
    }
    for(int i=1;i<=n;i++)
    {
        if(a[i]==0&&b[x+i]==0&&c[x-i+20]==0)
        {
            a[i]=1,b[x+i]=1,c[x-i+20]=1;
            ans2[x]=i;
            dfs(x+1);
            a[i]=0,b[x+i]=0,c[x-i+20]=0;
        }
    }
}
int main()
{
    cin>>n;
    dfs(1);
    cout<<ans;
}
